import React, { useState, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { Github, Twitter, Menu, X, BrainCircuit, Sparkles, Globe } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { useLanguage } from '../../i18n/LanguageContext';
import { AiChatBubble } from './AiChatBubble';

export const Header: React.FC = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const { language, toggleLanguage, t } = useLanguage();
  const navigate = useNavigate();
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleNavigation = (e: React.MouseEvent<HTMLAnchorElement>, targetId: string) => {
    e.preventDefault();
    if (location.pathname !== '/') {
      navigate('/', { state: { scrollTo: targetId } });
    } else {
      const element = document.getElementById(targetId);
      if (element) {
        element.scrollIntoView({ behavior: 'smooth' });
      }
    }
    setIsMobileMenuOpen(false);
  };

  return (
    <>
      <motion.header
        initial={{ y: -100, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
        transition={{ duration: 0.5 }}
        className={`fixed top-0 left-0 right-0 z-50 flex justify-center w-full transition-all duration-300 bg-macaron-pink h-16`}
      >
        <div className={`
          flex items-center justify-between px-6 py-3 w-full max-w-[1440px]
          transition-all duration-300
        `}>
          {/* Left Nav */}
          <nav className="hidden md:flex items-center gap-8">
            <Link to="/" className="flex items-center gap-2 font-medium text-black group mr-4">
              <span className="font-bold text-lg font-logo">Google Labs</span>
            </Link>
            <a href="#projects" onClick={(e) => handleNavigation(e, 'projects')} className="text-sm font-medium text-black hover:opacity-70 transition-opacity">
              {t('nav.projects')}
            </a>
            <a href="#thoughts" onClick={(e) => handleNavigation(e, 'thoughts')} className="text-sm font-medium text-black hover:opacity-70 transition-opacity">
              {t('nav.thoughts')}
            </a>
            <a href="#contact" onClick={(e) => handleNavigation(e, 'contact')} className="text-sm font-medium text-black hover:opacity-70 transition-opacity">
              {language === 'en' ? 'Community' : '社区'}
            </a>
          </nav>

          {/* Mobile Logo (Centered if nav hidden) */}
          <Link to="/" className="md:hidden flex items-center gap-2 font-bold text-lg text-black font-logo">
            Google Labs
          </Link>

          {/* Right Icons */}
          <div className="flex items-center gap-4 text-black">
            <button 
              onClick={toggleLanguage}
              className="hover:opacity-70 transition-opacity flex items-center justify-center w-8 h-8 rounded-full border border-black/10 hover:bg-black/5"
              title={language === 'en' ? 'Switch to Chinese' : 'Switch to English'}
            >
              <span className="text-xs font-bold font-mono">
                {language === 'en' ? 'CN' : 'EN'}
              </span>
            </button>
            
            {/* Social Icons (Desktop Only) */}
            <div className="hidden md:flex items-center gap-4">
              {/* Icons removed */}
            </div>

            {/* Mobile Menu Button */}
            <button 
              className="md:hidden hover:opacity-70 transition-opacity"
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
            >
              {isMobileMenuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
            </button>
          </div>
        </div>
      </motion.header>

      {/* Mobile Menu Overlay */}
      <AnimatePresence>
        {isMobileMenuOpen && (
          <motion.div
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            className="fixed inset-0 z-40 bg-macaron-cream/95 backdrop-blur-lg pt-24 px-6 md:hidden flex flex-col items-center"
          >
            <nav className="flex flex-col gap-6 w-full text-center">
              {[
                { id: 'projects', label: t('nav.projects') },
                { id: 'thoughts', label: t('nav.thoughts') },
                { id: 'contact', label: t('nav.contact') }
              ].map((item) => (
                <a 
                  key={item.id}
                  href={`#${item.id}`}
                  onClick={(e) => handleNavigation(e, item.id)}
                  className="text-2xl font-bold text-macaron-text py-2 hover:text-macaron-pink transition-colors"
                >
                  {item.label}
                </a>
              ))}
            </nav>
          </motion.div>
        )}
      </AnimatePresence>
      
      {/* AI Chat Bubble - Global */}
      <AiChatBubble />
    </>
  );
};
